"use client"

import { useState, useCallback, useEffect } from "react"
import { Button } from "@/components/ui/button"
import { AgendaHeader } from "./agenda-header"
import { AgendaGrid, type Appointment } from "./agenda-grid"
import { NovoAgendamentoModal, type NovoAgendamento } from "./novo-agendamento-modal"
import { CheckCircle, X } from "lucide-react"
import { useSubscription } from "@/contexts/subscription-context"
import { useSalonData } from "@/contexts/salon-data-context"
import { useAuth } from "@/contexts/auth-context"

const mockProfessionals = [
  {
    id: "1",
    initials: "AS",
    name: "Aline de Abreu Souza",
    especialidades: ["Alongamento de Cílios", "Design de Sobrancelhas"],
    isAuxiliar: false,
    vinculoProfissionalId: undefined as string | undefined,
  },
  {
    id: "2",
    initials: "AJ",
    name: "Ana Carolina dos Santos Jarek",
    especialidades: ["Manicure Clássica", "Manicure Avançada"],
    isAuxiliar: false,
    vinculoProfissionalId: undefined as string | undefined,
  },
  {
    id: "3",
    initials: "CM",
    name: "Conceição Aparecida de Morais",
    especialidades: ["Cabelo", "Maquiagem"],
    isAuxiliar: false,
    vinculoProfissionalId: undefined as string | undefined,
  },
  {
    id: "4",
    initials: "CS",
    name: "Cleiry Aparecida da Silva",
    especialidades: ["Barbearia", "Cabelo"],
    isAuxiliar: true,
    vinculoProfissionalId: "1",
  },
  {
    id: "5",
    initials: "CF",
    name: "Cleuza Ferreira",
    especialidades: ["Depilação à Cera", "Podologia"],
    isAuxiliar: true,
    vinculoProfissionalId: undefined as string | undefined,
  },
]

const initialAppointments: Appointment[] = [
  {
    id: "1",
    professionalId: "1",
    clientName: "Raissa Antunes",
    startTime: "19:30",
    endTime: "20:00",
    serviceType: "Alongamento Tipo 1",
    auxiliarId: "4",
    auxiliarName: "Cleiry Aparecida da Silva",
  },
  {
    id: "2",
    professionalId: "3",
    clientName: "Maria Silva",
    startTime: "10:00",
    endTime: "11:00",
    serviceType: "Escova + Hidratacao",
  },
  {
    id: "3",
    professionalId: "2",
    clientName: "Julia Santos",
    startTime: "14:00",
    endTime: "15:30",
    serviceType: "Manicure e Pedicure",
    auxiliarId: "5",
    auxiliarName: "Cleuza Ferreira",
  },
]

export function AgendaPage() {
  const { isBlocked } = useSubscription()
  const { salonData, isNewSalon } = useSalonData()
  const { selectedSalon, user } = useAuth()

  // Check if this is a mock salon or new salon
  const isMockSalon = selectedSalon && ["1", "2", "3", "4", "5"].includes(selectedSalon.id)

  // Get professionals based on salon type
  const getInitials = (name: string | undefined | null) => {
    if (!name) return "??"
    const parts = name.trim().split(" ")
    if (parts.length >= 2) {
      return (parts[0][0] + parts[parts.length - 1][0]).toUpperCase()
    }
    return name.substring(0, 2).toUpperCase()
  }

  // For real salons, use salon owner as the professional with their especialidades
  const professionalName = user?.nome || selectedSalon?.nome || "Profissional"

  // Get especialidades from salonData.usuarios[0] or salonData.especialidades
  const professionalEspecialidades = (() => {
    const userEsp = salonData?.usuarios?.[0]?.especialidade
    if (Array.isArray(userEsp) && userEsp.length > 0) return userEsp
    // Fallback: use all especialidades from salon
    return salonData?.especialidades?.map(e => e.nome) ?? []
  })()

  const realSalonProfessionals = selectedSalon && !isMockSalon ? [
    {
      id: selectedSalon.id,
      initials: getInitials(professionalName),
      name: professionalName,
      especialidades: professionalEspecialidades,
    }
  ] : []

  const professionals = isMockSalon ? mockProfessionals : realSalonProfessionals

  // Get initial appointments based on salon type
  const getInitialAppointments = (): Appointment[] => {
    if (isBlocked) return []
    if (isMockSalon) return initialAppointments
    // For new salons, start with empty appointments
    return []
  }

  // Get initial date based on next appointment or today
  const getInitialDate = (): Date => {
    const today = new Date()
    today.setHours(0, 0, 0, 0)

    // Check salonData agendamentos for future appointments
    const agendamentos = salonData?.agendamentos ?? []
    const futureAgendamentos = agendamentos
      .filter(a => {
        const agendamentoDate = new Date(a.data)
        agendamentoDate.setHours(0, 0, 0, 0)
        return agendamentoDate >= today && a.status !== "cancelado"
      })
      .sort((a, b) => new Date(a.data).getTime() - new Date(b.data).getTime())

    if (futureAgendamentos.length > 0) {
      return new Date(futureAgendamentos[0].data)
    }

    return today
  }

  const [currentDate, setCurrentDate] = useState(() => getInitialDate())
  const [filteredEspecialidades, setFilteredEspecialidades] = useState<string[]>([])
  const [filteredProfissionais, setFilteredProfissionais] = useState<string[]>([])
  const [filteredStatus, setFilteredStatus] = useState<string[]>([])
  const [showOnlyMyTeam, setShowOnlyMyTeam] = useState(false)
  const [showOnlyAuxiliares, setShowOnlyAuxiliares] = useState(false)
  const [isNovoAgendamentoModalOpen, setIsNovoAgendamentoModalOpen] = useState(false)
  const [appointments, setAppointments] = useState<Appointment[]>(getInitialAppointments())
  const [toast, setToast] = useState<{ show: boolean; message: string }>({ show: false, message: "" })

  // Check if any professionals are auxiliares
  const hasAuxiliares = professionals.some((p) => p.isAuxiliar)

  // Update appointments when salon changes
  useEffect(() => {
    setAppointments(getInitialAppointments())
  }, [selectedSalon, isMockSalon, isBlocked])

  // Listen for event to open novo agendamento modal (from first agendamento flow)
  useEffect(() => {
    const handleOpenModal = () => {
      setIsNovoAgendamentoModalOpen(true)
    }
    window.addEventListener("openNovoAgendamentoModal", handleOpenModal)
    return () => window.removeEventListener("openNovoAgendamentoModal", handleOpenModal)
  }, [])

  const handlePrevDay = () => {
    setCurrentDate((prev) => {
      const newDate = new Date(prev)
      newDate.setDate(newDate.getDate() - 1)
      return newDate
    })
  }

  const handleNextDay = () => {
    setCurrentDate((prev) => {
      const newDate = new Date(prev)
      newDate.setDate(newDate.getDate() + 1)
      return newDate
    })
  }

  const handleToday = () => {
    setCurrentDate(new Date())
  }

  const handleDateChange = useCallback((date: Date) => {
    setCurrentDate(date)
  }, [])

  const handleEspecialidadesChange = useCallback((especialidades: string[]) => {
    setFilteredEspecialidades(especialidades)
  }, [])

  const handleProfissionaisChange = useCallback((profissionais: string[]) => {
    setFilteredProfissionais(profissionais)
  }, [])

  const handleStatusChange = useCallback((status: string[]) => {
    setFilteredStatus(status)
  }, [])

  const handleCreateAppointment = useCallback(
    (novoAgendamento: NovoAgendamento) => {
      if (isBlocked) return

      const profissional = professionals.find((p) => p.name === novoAgendamento.professionalName)

      const newAppointment: Appointment = {
        id: novoAgendamento.id,
        professionalId: profissional?.id || novoAgendamento.professionalId,
        clientName: novoAgendamento.clientName,
        startTime: novoAgendamento.startTime,
        endTime: novoAgendamento.endTime,
        serviceType: novoAgendamento.serviceName,
      }

      setAppointments((prev) => [...prev, newAppointment])

      setToast({
        show: true,
        message: `Agendamento criado com sucesso para ${novoAgendamento.clientName}!`,
      })

      setTimeout(() => {
        setToast({ show: false, message: "" })
      }, 4000)
    },
    [isBlocked],
  )

  const handleUpdateAppointment = useCallback((updatedAppointment: Appointment) => {
    setAppointments((prev) =>
      prev.map((appointment) => (appointment.id === updatedAppointment.id ? updatedAppointment : appointment)),
    )
  }, [])

  const handleDeleteAppointment = useCallback((appointmentId: string) => {
    setAppointments((prev) => prev.filter((appointment) => appointment.id !== appointmentId))
  }, [])

  const filteredProfessionals = professionals.filter((prof) => {
    const passEspecialidades =
      filteredEspecialidades.length === 0 || prof.especialidades.some((esp) => filteredEspecialidades.includes(esp))

    const passProfissionais = filteredProfissionais.length === 0 || filteredProfissionais.includes(prof.id)

    // Auxiliar filter: show only auxiliares
    const passAuxiliar = !showOnlyAuxiliares || prof.isAuxiliar

    // Team filter: for a linked auxiliar, show only themselves + their linked professional
    // For a professional, show only themselves + their linked auxiliares
    let passTeam = true
    if (showOnlyMyTeam) {
      // Find auxiliares linked to specific professionals
      const linkedAuxiliares = professionals.filter(
        (p) => p.isAuxiliar && p.vinculoProfissionalId
      )
      // Find all team connections
      const isInTeam = linkedAuxiliares.some(
        (aux) =>
          (aux.id === prof.id) ||
          (aux.vinculoProfissionalId === prof.id)
      )
      passTeam = isInTeam
    }

    return passEspecialidades && passProfissionais && passAuxiliar && passTeam
  })

  return (
    <div className="flex-1 w-full p-4 md:p-6 pb-5">
      {toast.show && (
        <div className="fixed top-4 right-4 z-50 animate-in slide-in-from-top-2 fade-in duration-300">
          <div className="bg-green-50 border border-green-200 rounded-lg shadow-lg p-4 flex items-center gap-3 min-w-[300px]">
            <CheckCircle className="w-5 h-5 text-green-600 flex-shrink-0" />
            <span className="text-sm text-green-800 flex-1">{toast.message}</span>
            <button
              onClick={() => setToast({ show: false, message: "" })}
              className="text-green-600 hover:text-green-800 cursor-pointer"
            >
              <X className="w-4 h-4" />
            </button>
          </div>
        </div>
      )}

      {/* Header — padrão igual /admin/salons */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-6">
        <div>
          <h1 className="text-xl md:text-2xl font-semibold text-foreground">Agenda</h1>
          <p className="text-sm text-muted-foreground mt-1">Gerencie os agendamentos do salão</p>
        </div>
        <Button
          className="bg-primary hover:bg-primary/90 text-primary-foreground cursor-pointer w-full md:w-auto"
          onClick={() => setIsNovoAgendamentoModalOpen(true)}
        >
          Novo Agendamento
        </Button>
      </div>

      <AgendaHeader
        date={currentDate}
        onPrevDay={handlePrevDay}
        onNextDay={handleNextDay}
        onToday={handleToday}
        onDateChange={handleDateChange}
        onEspecialidadesChange={handleEspecialidadesChange}
        onProfissionaisChange={handleProfissionaisChange}
        onStatusChange={handleStatusChange}
        showQuickFilters={isMockSalon && hasAuxiliares}
        showOnlyMyTeam={showOnlyMyTeam}
        showOnlyAuxiliares={showOnlyAuxiliares}
        onToggleMyTeam={() => {
          setShowOnlyMyTeam(!showOnlyMyTeam)
          if (!showOnlyMyTeam) setShowOnlyAuxiliares(false)
        }}
        onToggleAuxiliares={() => {
          setShowOnlyAuxiliares(!showOnlyAuxiliares)
          if (!showOnlyAuxiliares) setShowOnlyMyTeam(false)
        }}
        onClearQuickFilters={() => {
          setShowOnlyMyTeam(false)
          setShowOnlyAuxiliares(false)
        }}
      />

      <AgendaGrid
        currentDate={currentDate}
        professionals={filteredProfessionals}
        appointments={appointments}
        onUpdateAppointment={handleUpdateAppointment}
        onDeleteAppointment={handleDeleteAppointment}
      />

      <NovoAgendamentoModal
        isOpen={isNovoAgendamentoModalOpen}
        onClose={() => setIsNovoAgendamentoModalOpen(false)}
        onSubmit={handleCreateAppointment}
        professionals={professionals}
        currentDate={currentDate}
      />
    </div>
  )
}

