const especialidades = [
  "Alongamento de Cílios",
  "Barbearia",
  "Cabelo",
  "Depilação à Cera",
  "Design de Sobrancelhas",
  "Extensionista",
  "Manicure Avançada",
  "Manicure Clássica",
  "Maquiagem",
  "Micropigmentação",
  "Podologia",
  "Teste",
  "Outros Serviços",
]

const profissionais = [
  "Aline de Abreu Souza",
  "Ana Carolina dos Santos Jarek",
  "Conceição Aparecida de Morais",
  "Cleiry Aparecida da Silva",
  "Cleuza Ferreira",
]

const statusOptions = ["Agendado", "Atendendo", "Pgto pendente", "Pago", "Cancelado"]

export function AgendaHeader({
  date,
  onPrevDay,
  onNextDay,
  onToday,
  onDateChange,
  onEspecialidadesChange,
  onProfissionaisChange,
  onStatusChange,
  showQuickFilters = false,
  showOnlyMyTeam = false,
  showOnlyAuxiliares = false,
  onToggleMyTeam,
  onToggleAuxiliares,
  onClearQuickFilters,
}: AgendaHeaderProps) {
  const [especialidadesOpen, setEspecialidadesOpen] = useState(false)
  const [selectedEspecialidades, setSelectedEspecialidades] = useState<string[]>([])
  const [searchTerm, setSearchTerm] = useState("")

  const [calendarOpen, setCalendarOpen] = useState(false)
  const [calendarDrawerOpen, setCalendarDrawerOpen] = useState(false)
  const calendarRef = useRef<HTMLDivElement>(null)

  const [profissionaisOpen, setProfissionaisOpen] = useState(false)
  const [selectedProfissionais, setSelectedProfissionais] = useState<string[]>([])
  const [profissionaisSearchTerm, setProfissionaisSearchTerm] = useState("")
  const profissionaisRef = useRef<HTMLDivElement>(null)

  const [statusOpen, setStatusOpen] = useState(false)
  const [selectedStatus, setSelectedStatus] = useState<string[]>([])
  const statusRef = useRef<HTMLDivElement>(null)

  const dropdownRef = useRef<HTMLDivElement>(null)

  // Mobile filter drawer
  const [filterDrawerOpen, setFilterDrawerOpen] = useState(false)

  const totalFilters =
    selectedEspecialidades.length + selectedProfissionais.length + selectedStatus.length +
    (showOnlyMyTeam ? 1 : 0) + (showOnlyAuxiliares ? 1 : 0)

  const formatDate = (date: Date) => {
    if (!date) return ""
    const options: Intl.DateTimeFormatOptions = {
      day: "numeric",
      month: "long",
      year: "numeric",
      weekday: "long",
    }
    const formatted = date.toLocaleDateString("pt-BR", options)
    const parts = formatted.split(", ")
    return `${parts[0]} (${parts[1]})`
  }

  const formatDateShort = (date: Date) => {
    if (!date) return ""
    return date.toLocaleDateString("pt-BR", { day: "2-digit", month: "short" })
  }

  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setEspecialidadesOpen(false)
