type GetScheduleBreaksParams = {
  professional: User;
  selectedDate: Date;
  salonTimezone: string;
};

type ScheduleBreakResult = {
  id: string;
  start: string;
  end: string;
  type: "ausencia" | "indisponibilidade";
  reason?: string;
};

const getScheduleBreaksForDate = ({
  professional,
  selectedDate,
  salonTimezone,
}: GetScheduleBreaksParams): ScheduleBreakResult[] => {
  if (!professional.schedule) {
    return [];
  }

  // Normalize schedule to handle both numeric keys and day names
  const normalizedSchedule = normalizeSchedule(professional.schedule);
  if (!normalizedSchedule) {
    return [];
  }

  const dayOfWeek = selectedDate.getUTCDay();
  const dayMap: Record<number, keyof typeof normalizedSchedule> = {
    0: "sunday",
    1: "monday",
    2: "tuesday",
    3: "wednesday",
    4: "thursday",
    5: "friday",
    6: "saturday",
  };

  const dayName = dayMap[dayOfWeek];
  const daySchedule = normalizedSchedule[dayName];

  if (!daySchedule?.breaks || daySchedule.breaks.length === 0) {
    return [];
  }

  const dateString = format(selectedDate, "yyyy-MM-dd");
  const breaks = daySchedule.breaks.map(
    (breakPeriod: { start: string; end: string }, index: number) => {
      const startLocal = `${dateString}T${breakPeriod.start}:00`;
      const endLocal = `${dateString}T${breakPeriod.end}:00`;

      const startUTC = fromZonedTime(startLocal, salonTimezone);
      const endUTC = fromZonedTime(endLocal, salonTimezone);

      return {
        id: `schedule-break-${professional.id}-${dayOfWeek}-${index}`,
        start: startUTC.toISOString(),
        end: endUTC.toISOString(),
        type: "indisponibilidade" as const,
        reason: "Intervalo de descanso",
      };
    }
  );

  return breaks;
};

