   329→          setProfessionals(filteredProfessionals);
   330→          onFilteredProfessionalsChange?.(filteredProfessionals);
   331→        } catch (err) {
   332→          setProfessionals(allProfessionals);
   333→          onFilteredProfessionalsChange?.(allProfessionals);
   334→        }
   335→        return;
   336→      }
   337→
   338→      // Se não há especialidade selecionada ou é "all", mostra todos os profissionais
   339→      if (!selectedSpecialty || selectedSpecialty === "all") {
   340→        setProfessionals(allProfessionals);
   341→        onFilteredProfessionalsChange?.(allProfessionals);
   342→        return;
   343→      }
   344→
   345→      // Caso especial para "Outros"
   346→      if (selectedSpecialty === 'outros') {
   347→        setProfessionals(allProfessionals);
   348→        onFilteredProfessionalsChange?.(allProfessionals);
   349→        return;
   350→      }
   351→
   352→      // Se há apenas especialidade selecionada (sem serviço específico)
   353→      // Buscar todos os profissionais que trabalham com qualquer serviço desta especialidade
   354→      const specialty = specialties.find(s => s.id === selectedSpecialty);
   355→
   356→      if (!specialty) {
   357→        setProfessionals(allProfessionals);
   358→        onFilteredProfessionalsChange?.(allProfessionals);
   359→        return;
   360→      }
   361→
   362→      // Se a especialidade não tem serviços, mostra lista vazia (nenhum profissional trabalha com ela)
   363→      if (specialty.services.length === 0) {
   364→        setProfessionals([]);
   365→        onFilteredProfessionalsChange?.([]);
   366→        return;
   367→      }
   368→
   369→      // Buscar profissionais para cada serviço da especialidade
   370→      try {
   371→        const professionalsByService = await Promise.all(
   372→          specialty.services.map(async (service) => {
   373→            // Usar cache se disponível
   374→            if (professionalsByServiceCache.has(service.id)) {
   375→              const cachedProfs = professionalsByServiceCache.get(service.id)!;
   376→              return cachedProfs;
   377→            }
   378→
   379→            try {
   380→              const profs = await serviceService.getProfessionals(service.id);
   381→              const mappedProfs = profs.map((prof: any) => ({
   382→                id: prof.userId || prof.professionalId || prof.id,
   383→                name: prof.userName || prof.professionalName || prof.name || 'Profissional'
   384→              }));
   385→
   386→              // Adicionar ao cache
   387→              professionalsByServiceCache.set(service.id, mappedProfs);
   388→
   389→              return mappedProfs;
   390→            } catch {
   391→              return [];
   392→            }
   393→          })
   394→        );
   395→
   396→        // Combinar e remover duplicatas
   397→        const allServiceProfessionals = professionalsByService.flat();
   398→        filteredProfessionals = Array.from(
   399→          new Map(allServiceProfessionals.map(prof => [prof.id, prof])).values()
   400→        );
   401→
   402→        // Sempre usa os profissionais filtrados, mesmo que vazio
   403→        // Isso garante que a mensagem "Nenhum profissional disponível" apareça quando apropriado
   404→        setProfessionals(filteredProfessionals);
   405→        onFilteredProfessionalsChange?.(filteredProfessionals);
   406→      } catch (err) {
   407→        setProfessionals(allProfessionals);
   408→        onFilteredProfessionalsChange?.(allProfessionals);
   409→      }
   410→    };
   411→
   412→    // Só executar se não for um profissional (profissionais não veem o filtro)
   413→    if (userRole !== 'Profissional' && allProfessionals.length > 0) {
   414→      filterProfessionalsBySpecialty();
   415→    }
   416→    // eslint-disable-next-line react-hooks/exhaustive-deps
   417→  }, [selectedSpecialty, selectedServices, allProfessionals, specialties, userRole, professionalsByServiceCache]); // onFilteredProfessionalsChange omitido intencionalmente para evitar loops
   418→
   419→  const handleSpecialtySelect = (specialtyId: string): void => {
