   435→      onServiceFilter(serviceIds.length > 0 ? serviceIds : null);
   436→    }
   437→  };
   438→
   439→  const handleServiceToggle = (serviceId: string): void => {
   440→    const newSelection = selectedServices.includes(serviceId)
   441→      ? selectedServices.filter(id => id !== serviceId)
   442→      : [...selectedServices, serviceId];
   443→
   444→    setSelectedServices(newSelection);
   445→    if (onServiceFilter) {
   446→      onServiceFilter(newSelection.length > 0 ? newSelection : null);
   447→    }
   448→  };
   449→
   450→  const handleProfessionalToggle = (professionalId: string): void => {
   451→    if (professionalId === "all") {
   452→      setSelectedProfessionals([]);
   453→      onProfessionalFilter(null);
   454→    } else {
   455→      const newSelection = selectedProfessionals.includes(professionalId)
   456→        ? selectedProfessionals.filter(id => id !== professionalId)
   457→        : [...selectedProfessionals, professionalId];
   458→
   459→      setSelectedProfessionals(newSelection);
   460→      onProfessionalFilter(newSelection.length > 0 ? newSelection : null);
   461→    }
   462→  };
   463→
   464→  const handleStatusSelect = (status: string): void => {
   465→    const finalStatus = status === "all" ? null : status;
   466→    setSelectedStatus(finalStatus);
   467→    onStatusFilter(finalStatus);
   468→  };
   469→
   470→  const clearFilters = (): void => {
   471→    setSelectedSpecialty(null);
   472→    setSelectedServices([]);
   473→    setSelectedStatus(null);
   474→    setSearchQuery("");
   475→    setProfessionalSearchQuery("");
   476→    onStatusFilter(null);
