import { ReactNode } from "react";
import { cn } from "@/lib/utils";
interface PageHeaderProps {
  title: string;
  disabledActions?: boolean;
  subtitle?: string;
  action?: {
    label: string;
    onClick: () => void;
    variant?: "primary" | "secondary";
    className?: string;
  };
  children?: ReactNode;
}
export function PageHeader({
  title,
  subtitle,
  action,
  children,
  disabledActions = false,
}: PageHeaderProps) {
  return (
    <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-3 md:gap-4 mb-6"> {/* RESP: Breakpoint md e gaps responsivos */}
      <div>
        <h1 className="text-xl md:text-2xl font-semibold text-foreground">{title}</h1>
        {subtitle && <p className="text-sm text-muted-foreground mt-1">{subtitle}</p>}
      </div>

      <div className="flex items-center gap-3 w-full md:w-auto">
        {children}
        {action && (
          <button
            disabled={disabledActions}
            onClick={action.onClick}
            className={cn(
              "h-10 px-4 rounded-[14px] text-sm font-medium transition-colors disabled:opacity-50 disabled:cursor-not-allowed w-full md:w-auto",
              action.variant === "secondary"
                ? "border border-border bg-card hover:bg-muted text-foreground"
                : "bg-[#dd4227] hover:bg-[#c73a22] text-white",
              action.className
            )}
          >
            {action.label}
          </button>
        )}
      </div>
    </div>
  );
}

