  const [modalKey, setModalKey] = useState(0);
  const [modalEditarAgendamento, setModalEditarAgendamento] = useState(false);
  const [modalNovaAusencia, setModalNovaAusencia] = useState(false);
  const [modalComanda, setModalComanda] = useState(false);
  const [selectedAppointment, setSelectedAppointment] =
    useState<Appointment | null>(null);
  const [selectedProfessionalId, setSelectedProfessionalId] =
    useState<string>("");
  const [selectedTime, setSelectedTime] = useState<string>("");
  const [isEditingAbsence, setIsEditingAbsence] = useState(false);
  const [selectedAbsenceId, setSelectedAbsenceId] = useState<string>("");
  const [selectedAbsenceEndTime, setSelectedAbsenceEndTime] = useState<string>("");
  const [selectedAbsenceReason, setSelectedAbsenceReason] = useState<string>("");
  const [initialClientId, setInitialClientId] = useState<string>("");
  const [showFirstAppointmentModal, setShowFirstAppointmentModal] = useState(false);
  const [testClientOnboarding, setTestClientOnboarding] = useState<{ id: string; name: string; phone: string } | null>(null);
  const [professionalIdOnboarding, setProfessionalIdOnboarding] = useState<string | null>(null);
  const [calendarDrawerOpen, setCalendarDrawerOpen] = useState(false);
  const [focusAppointment, setFocusAppointment] = useState<{ id: string; time: string; professionalId: string } | null>(null);
  const [isFirstOnboardingAppointment, setIsFirstOnboardingAppointment] = useState(false);

  // Comanda modal data
  type ComandaService = {
    id: string;
    serviceName: string;
    startTime: string;
    endTime: string;
    professional: string;
    price: number;
    status: "Agendado" | "Atendendo" | "Pgto Pendente" | "Pago" | "Cancelado";
  };

  type ComandaData = {
    clientName: string;
    date: string;
    services: ComandaService[];
  };

  const [comandaData, setComandaData] = useState<ComandaData>({
    clientName: "",
    date: "",
    services: [],
  });

  const dateString = format(selectedDate, "yyyy-MM-dd");

  const { appointments, refresh: refreshAppointments } = useRealtimeAppointments({
    date: selectedDate,
    professionalIds: professionalFilter || undefined,
    specialtyServiceIds: serviceFilter || undefined,
    suppressCreatedToast: location.state?.mode === 'awaiting_ai',
  });

  useEffect(() => {
    analytics.trackEvent("agenda_viewed", { view_type: isMobile ? "daily" : "weekly" });
  }, [isMobile]);

  const handleAppointmentCreated = (appointment?: { id: string; date: string; time: string; professionalId: string }): void => {
    analytics.trackEvent("agendamento_realizado_internal", { booking_source: "salon" });
    refreshAppointments();

    if (isFirstOnboardingAppointment && appointment) {
      // Navegar para a data do agendamento (garantir que format bate com o esperado)
      setSelectedDate(new Date(appointment.date + 'T12:00:00')); // T12 para evitar problemas de timezone na data

      // Setar o foco
      setFocusAppointment(appointment);

      // Consumir o flag
      setIsFirstOnboardingAppointment(false);
    }
  };


  useWowMoment({
    setSelectedDate,
    refreshAppointments,
  });

  const { absences, refresh: refreshAbsences } = useRealtimeAbsences({
    date: selectedDate,
  });

  // Next Appointment Date Logic
  useEffect(() => {
    const fetchNextAppointment = async () => {
      if (!selectedSalon?.id) return;
      try {
        // Get start of today in ISO format to include appointments that started earlier today
        const startOfToday = new Date();
        startOfToday.setHours(0, 0, 0, 0);

        const response = await appointmentService.list({
          startDate: startOfToday.toISOString(),
          limit: 1,
          sortBy: "startTime",
          sortOrder: "ASC",
        });

        if (response.data && response.data.length > 0) {
          const firstApt = response.data[0];
          const firstAptDate = new Date(firstApt.startTime);

          // Se estivermos na data padrão (hoje), e houver um agendamento futuro (ou hoje), pular para ele
          // Pular apenas se a data for diferente do hoje absoluto para evitar loops, 
          // e se a data selecionada ainda for o "hoje" inicial.
          const today = new Date();
          if (firstAptDate.toDateString() !== today.toDateString() && 
              selectedDate.toDateString() === today.toDateString()) {
            setSelectedDate(firstAptDate);
          }
        }
      } catch (error) {
        console.error("Error fetching next appointment:", error);
      }
    };

    fetchNextAppointment();
  }, [selectedSalon?.id]);

  // Extract timezone into dedicated memo for reactivity
  const salonTimezone = useMemo(
    () => selectedSalon?.timezone || "America/Sao_Paulo",
    [selectedSalon?.timezone]
  );

  useEffect(() => {
    const loadSalonData = async (): Promise<void> => {
      if (!selectedSalon?.id) return;

      // STRICT CHECK: Ensure the selectedSalon matches the persisted one to avoid race conditions
      // This prevents the "old" salon from being used just before the new one loads
      const storedSalonId = localStorage.getItem("selectedSalonId");
      if (storedSalonId && selectedSalon.id !== storedSalonId) {
        return;
      }

      setLoading(true);
      try {
        const [professionalsResponse, operatingHoursData, servicesResponse] = await Promise.all([
          userService.list({
            salonId: selectedSalon.id,
            role: UserRole.PROFISSIONAL,
            status: "active",
          }),
          agendaService.getSalonOperatingHours(selectedSalon.id),
          serviceService.getAll({ salonId: selectedSalon.id, active: true }),
        ]);

        setProfessionals(professionalsResponse.data);
        setFilteredProfessionals(professionalsResponse.data);
        setOperatingHours(operatingHoursData);

        // Process services
        let allServices = [];
        if (servicesResponse.customServices || servicesResponse.standardServices) {
          allServices = [
            ...(servicesResponse.customServices || []),
            ...(servicesResponse.standardServices || []),
          ];
        } else if (Array.isArray(servicesResponse)) {
          allServices = servicesResponse;
        }
        setSalonServices(allServices);
      } catch (error) {
        console.error("Error loading salon data:", error);
      } finally {
        setLoading(false);
      }
    };

    if (selectedSalon?.id) {
      loadSalonData();
    } else {
      setLoading(false);
    }
  }, [selectedSalon?.id]);



  // Calculate operating hours for selected date
  const salonDaySchedule = useMemo(() => {
    if (!operatingHours) {
      return { startHour: 8, endHour: 20, isOpen: true };
    }

    const dayOfWeek = selectedDate.getDay();
    const daySchedule = operatingHours.openingHours.find(
      (h) => h.dayOfWeek === dayOfWeek
    );

    if (!daySchedule) {
      return { startHour: 8, endHour: 20, isOpen: false };
    }

    if (!daySchedule.isOpen) {
      return { startHour: 8, endHour: 20, isOpen: false };
    }

    const [openHour] = daySchedule.open.split(":").map(Number);
    const [closeHour] = daySchedule.close.split(":").map(Number);

    return {
      startHour: openHour,
      endHour: closeHour,
      isOpen: true,
    };
  }, [operatingHours, selectedDate]);

  // Calcular slotMinutes baseado nas configurações do salão e durações dos serviços
  const slotMinutes = useMemo(() => {
    // Obter slotInterval das configurações do salão (padrão: 15)
    const salonSlotInterval = operatingHours?.settings?.slotInterval || 15;

    // Se não tiver serviços carregados, usar o slotInterval do salão
    if (!salonServices || salonServices.length === 0) {
      return salonSlotInterval;
    }

    // Verificar se algum serviço tem duração menor que 30 minutos
    const hasShortService = salonServices.some((service) => {
      const duration = typeof service.duration === 'number'
        ? service.duration
        : parseInt(service.duration || '30', 10);
      return duration < 30;
    });

    // Verificar se algum profissional tem configuração customizada com duração < 30
    const hasProfessionalShortService = filteredProfessionals.some((professional) => {
      // Verificar se algum serviço tem customDuration para este profissional
      return salonServices.some((service) => {
        if (!service.professionals || service.professionals.length === 0) {
          return false;
        }

        // Buscar configuração customizada do profissional para este serviço
        const professionalConfig = service.professionals.find(
          (p) => p.professionalId === professional.id
        );

        if (professionalConfig?.customDuration) {
          return professionalConfig.customDuration < 30;
        }

        return false;
      });
    });

    // Se algum serviço ou configuração de profissional tiver < 15 minutos, usar slotInterval do salão
    // Caso contrário, otimizar para slots de 15 minutos
    return hasShortService || hasProfessionalShortService ? salonSlotInterval : 15;
  }, [salonServices, filteredProfessionals, operatingHours?.settings?.slotInterval]);

  // Filter professionals
  const displayedProfessionals = useMemo(() => {
    if (!professionalFilter || professionalFilter.length === 0) {
      return filteredProfessionals;
    }
    return filteredProfessionals.filter((prof) =>
      professionalFilter.includes(prof.id)
    );
  }, [filteredProfessionals, professionalFilter]);

  const columns: ProfessionalColumn[] = useMemo(() => {
    const selectedDateString = format(selectedDate, "yyyy-MM-dd");

    return displayedProfessionals.map((prof) => {
      const registeredAbsences = absences
        .filter((absence) => {
          if (absence.userId !== prof.id) return false;

          // Filter absences by date in salon timezone
          // formatInTimeZone handles the timezone conversion internally
          const absenceStartDate = formatInTimeZone(
            new Date(absence.startDate),
            salonTimezone,
            "yyyy-MM-dd"
          );
          const absenceEndDate = formatInTimeZone(
            new Date(absence.endDate),
            salonTimezone,
            "yyyy-MM-dd"
          );

          // Only include absences that start and end on the same selected date
          return (
            absenceStartDate === selectedDateString &&
            absenceEndDate === selectedDateString
          );
        })
        .map(transformAbsenceToBreak);

      const scheduleBreaks = getScheduleBreaksForDate({
        professional: prof,
        selectedDate,
        salonTimezone,
      });

      const allBreaks = [...registeredAbsences, ...scheduleBreaks];

      // Normalize schedule to ensure consistent format
      const normalizedSchedule = normalizeSchedule(prof.schedule);

      return {
        id: prof.id,
        name: prof.name,
        nickname: prof.nickname,
        avatar: prof.avatar,
        breaks: allBreaks,
        schedule: normalizedSchedule as any,
        salonDaySchedule: salonDaySchedule,
        salonTimezone,
      };
    });
  }, [
    displayedProfessionals,
    absences,
    salonDaySchedule,
    salonTimezone,
    selectedDate,
  ]);

  // Filter events by status (service filtering is done by the hook)
  const filteredEvents = useMemo(() => {
    let filtered = appointments;

    if (statusFilter) {
      filtered = filtered.filter((apt) => {
        const eventStatus = mapAppointmentStatusToEventStatus(apt.status, apt.paymentStatus);
        return eventStatus === statusFilter;
      });
    }

    return filtered.map(transformAppointmentToEvent);
  }, [appointments, statusFilter]);

  const handleEventClick = (event: CalendarEvent): void => {
    const appointment = event.rawData as Appointment;

    // Verificar se é um agendamento futuro
    const now = new Date();
    const appointmentStart = new Date(appointment.startTime);
    const isFuture = appointmentStart > now;

    if (isFuture) {
      // Para agendamentos futuros, abrir modal de edição
      setSelectedAppointment(appointment);
      setModalEditarAgendamento(true);
    } else {
      // Para agendamentos passados ou em andamento, abrir comanda para gerenciar pagamento
      openComandaModal(event);
    }
  };

  const handleSlotClick = (professionalId: string, startTime: string): void => {
    if (!professionalId || !startTime) {
      console.error("[handleSlotClick] Missing professionalId or startTime", {
        professionalId,
        startTime,
      });
      return;
    }

    setSelectedProfessionalId(professionalId);
    setSelectedTime(startTime);
    setInitialClientId(""); // Limpar client ID de onboarding ao clicar num slot normal
    setModalKey((prev) => prev + 1); // Forçar remount para resetar estado interno do modal
    setModalNovoAgendamento(true);
  };

  const handleAbsenceClick = (
    professionalId: string,
    startTime: string
  ): void => {
    if (!professionalId || !startTime) {
      console.error(
        "[handleAbsenceClick] Missing professionalId or startTime",
        {
          professionalId,
          startTime,
        }
      );
      return;
    }

    setSelectedProfessionalId(professionalId);
    setSelectedTime(startTime);
    setIsEditingAbsence(false);
    setSelectedAbsenceId("");
    setSelectedAbsenceEndTime("");
    setSelectedAbsenceReason("");
    setModalNovaAusencia(true);
  };

  const handleAbsenceBlockClick = (absenceData: AbsenceBlockData): void => {
    const professional = displayedProfessionals.find(
      (p) => p.id === absenceData.professionalId
    );

    if (!professional) {
      console.error("[handleAbsenceBlockClick] Professional not found");
      return;
    }

    setSelectedProfessionalId(absenceData.professionalId);
    setSelectedTime(absenceData.startTime);
    setIsEditingAbsence(true);
    setSelectedAbsenceId(absenceData.id);
    setSelectedAbsenceEndTime(absenceData.endTime);
    setSelectedAbsenceReason(absenceData.reason || "");
    setModalNovaAusencia(true);
  };

  const handleNewAppointment = (args?: { clientId?: string; professionalId?: string }): void => {
    // Define valores padrão quando criar agendamento sem clicar em slot específico
    const today = parseDateTz(new Date(), salonTimezone);
    let hour = today.getHours();
    const minutes = today.getMinutes();

    setSelectedAppointment(null);
    setInitialClientId(args?.clientId || "");
    setSelectedProfessionalId(args?.professionalId || "");

    const endHour = salonDaySchedule.endHour;
    const startHour = salonDaySchedule.startHour;

    // Regras de arredondamento:
    // ... (rest of rounding logic)
    let defaultMinutes: string;

    if (minutes < 15) {
      defaultMinutes = "00";
    } else if (minutes < 30) {
      defaultMinutes = "30";
    } else if (minutes < 45) {
      hour = hour + 1;
      defaultMinutes = "00";
    } else {
      hour = hour + 1;
      defaultMinutes = "30";
    }

    if (hour < startHour) {
      hour = startHour;
      defaultMinutes = "00";
    } else if (hour > endHour) {
      hour = endHour;
      defaultMinutes = "00";
    } else if (hour === endHour) {
      defaultMinutes = "00";
    }

    const defaultTime = `${hour}:${defaultMinutes}`;

    setSelectedTime(defaultTime);
    setSelectedProfessionalId(""); // Empty when clicking "Novo Agendamento" button

    if (args?.clientId) {
      setInitialClientId(args.clientId);
    } else {
      setInitialClientId("");
    }

    setModalKey((prev) => prev + 1); // Forçar remount para resetar estado interno do modal
    setModalNovoAgendamento(true);
  };
