type AppointmentWithExtras = Appointment & {
  clientName?: string;
  serviceName?: string;
  professionalName?: string;
  isOnlineBooking?: boolean;
};

const mapAppointmentStatusToEventStatus = (
  status: AppointmentStatus,
  paymentStatus?: string
): EventStatus => {
  // PRIORIDADE: Se paymentStatus é "paid", sempre retornar "Pago"
  // independente do status do agendamento
  if (paymentStatus === "paid") {
    return "Pago";
  }

  const statusMap: Record<AppointmentStatus, EventStatus> = {
    [AppointmentStatus.SCHEDULED]: "Agendado",
    [AppointmentStatus.CONFIRMED]: "Agendado",
    [AppointmentStatus.IN_PROGRESS]: "Atendendo",
    [AppointmentStatus.COMPLETED]: "Pgto Pendente",
    [AppointmentStatus.PAID]: "Pago",
    [AppointmentStatus.CANCELLED]: "Cancelado",
    [AppointmentStatus.NO_SHOW]: "Cancelado",
  };

  return statusMap[status] || "Agendado";
};

const transformAppointmentToEvent = (
  appointment: AppointmentWithExtras
): CalendarEvent => {
  // Obter os nomes reais do cliente e serviço
  const rawClientName = appointment.clientName || appointment.client?.name;
  const rawServiceName = appointment.serviceName || appointment.service?.name;


  // Detectar se é uma reserva (quando ambos são null, undefined, string vazia, ou "Unknown")
  // Reservas são bloqueios feitos pelo profissional sem cliente/serviço definido
  const isReserva =
    (!rawClientName || rawClientName === "Unknown") &&
    (!rawServiceName || rawServiceName === "Unknown");

  // Definir nomes de exibição com fallbacks apropriados
  // Para reservas, usar texto especial
  const clientName = isReserva ? "Reserva feita pelo profissional" : (rawClientName || "Cliente não definido");
  const serviceName = isReserva ? "" : (rawServiceName || "Serviço não definido");
  const professionalId = appointment.professionalId;

  // Verifica se é um agendamento online pelo campo source
  const isOnlineBooking = appointment.source === 'online';

  return {
    id: appointment.id,
    clientName,
    serviceName,
    professionalId,
    start:
      typeof appointment.startTime === "string"
        ? appointment.startTime
        : appointment.startTime.toISOString(),
    end:
      typeof appointment.endTime === "string"
        ? appointment.endTime
        : appointment.endTime.toISOString(),
    status: mapAppointmentStatusToEventStatus(appointment.status, appointment.paymentStatus),
    variant: isReserva ? "reserva" : (isOnlineBooking ? "online" : "default"),
    price: appointment.service?.price || appointment.price,
    isOnlineBooking,
    source: appointment.source,
    rawData: appointment,
  };
};

const transformAbsenceToBreak = (
  absence: Absence
): {
  id: string;
  start: string;
  end: string;
  type: "ausencia" | "indisponibilidade";
  reason?: string;
} => {
  return {
    id: absence.id,
    start: absence.startDate,
    end: absence.endDate,
    type: "ausencia",
    reason: absence.reason,
  };
};

type GetScheduleBreaksParams = {
  professional: User;
  selectedDate: Date;
  salonTimezone: string;
};

type ScheduleBreakResult = {
  id: string;
  start: string;
  end: string;
  type: "ausencia" | "indisponibilidade";
  reason?: string;
};

const getScheduleBreaksForDate = ({
  professional,
  selectedDate,
  salonTimezone,
}: GetScheduleBreaksParams): ScheduleBreakResult[] => {
  if (!professional.schedule) {
    return [];
  }

  // Normalize schedule to handle both numeric keys and day names
  const normalizedSchedule = normalizeSchedule(professional.schedule);
  if (!normalizedSchedule) {
    return [];
  }

  const dayOfWeek = selectedDate.getUTCDay();
  const dayMap: Record<number, keyof typeof normalizedSchedule> = {
    0: "sunday",
    1: "monday",
    2: "tuesday",
    3: "wednesday",
    4: "thursday",
    5: "friday",
    6: "saturday",
  };

  const dayName = dayMap[dayOfWeek];
  const daySchedule = normalizedSchedule[dayName];

  if (!daySchedule?.breaks || daySchedule.breaks.length === 0) {
    return [];
  }

  const dateString = format(selectedDate, "yyyy-MM-dd");
  const breaks = daySchedule.breaks.map(
    (breakPeriod: { start: string; end: string }, index: number) => {
      const startLocal = `${dateString}T${breakPeriod.start}:00`;
      const endLocal = `${dateString}T${breakPeriod.end}:00`;

      const startUTC = fromZonedTime(startLocal, salonTimezone);
      const endUTC = fromZonedTime(endLocal, salonTimezone);

      return {
        id: `schedule-break-${professional.id}-${dayOfWeek}-${index}`,
        start: startUTC.toISOString(),
        end: endUTC.toISOString(),
        type: "indisponibilidade" as const,
        reason: "Intervalo de descanso",
      };
    }
  );

  return breaks;
};

