const activeFilterChips = useMemo(() => {
  type ChipType = 'specialty' | 'professional' | 'status';
  const chips: Array<{ id: string; label: string; type: ChipType }> = [];
  if (specialtyLabel) chips.push({ id: 'specialty', label: specialtyLabel, type: 'specialty' });
  professionalChips.forEach(p => chips.push({ id: p.id, label: p.label.split(' ')[0], type: 'professional' }));
  if (statusFilter) chips.push({ id: statusFilter, label: statusFilter, type: 'status' });
  return chips;
}, [specialtyLabel, professionalChips, statusFilter]);

