"use client"

import { useState, useRef, useEffect } from "react"
import {
  IconChevronDown,
  IconUser,
  IconLogout,
  IconBuilding,
  IconLayoutDashboard,
  IconAlertCircle,
  IconRobot,
  IconAppWindow,
  IconNetwork,
  IconMenu2,
} from "@tabler/icons-react"
import { useSidebar } from "@/contexts/sidebar-context"
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip"
import {
  Drawer,
  DrawerContent,
  DrawerHeader,
  DrawerTitle,
} from "@/components/ui/drawer"

import Link from "next/link"
import { useRouter, usePathname } from "next/navigation"
import { useAuth } from "@/contexts/auth-context"
import { LoadingSpinner } from "@/components/ui/loading-spinner"

export function Header() {
  const router = useRouter()
  const pathname = usePathname()
  const { user, currentSalon, availableSalons, setCurrentSalon, logout, selectedSalon, selectedFranchise, setSelectedSalon, setSelectedFranchise } = useAuth()
  const { toggle: toggleSidebar } = useSidebar()
  const salonDropdownRef = useRef<HTMLDivElement>(null)
  const [userDropdownOpen, setUserDropdownOpen] = useState(false)
  const [salonDropdownOpen, setSalonDropdownOpen] = useState(false)
  const [salonDrawerOpen, setSalonDrawerOpen] = useState(false)
  const [isChangingSalon, setIsChangingSalon] = useState(false)
  const userDropdownRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (userDropdownRef.current && !userDropdownRef.current.contains(event.target as Node)) {
        setUserDropdownOpen(false)
      }
      if (salonDropdownRef.current && !salonDropdownRef.current.contains(event.target as Node)) {
        setSalonDropdownOpen(false)
      }
    }
    document.addEventListener("mousedown", handleClickOutside)
    return () => document.removeEventListener("mousedown", handleClickOutside)
  }, [])

  const handleLogout = () => {
    setUserDropdownOpen(false)
    logout()
    router.push("/login")
  }

  const handleSalonChange = async (salon: (typeof availableSalons)[0]) => {
    setIsChangingSalon(true)
    setSalonDropdownOpen(false)

    await new Promise((resolve) => setTimeout(resolve, 500))

    setSelectedSalon(salon)

    // Verificar se salão está bloqueado
    const isBlocked = ["none", "canceled", "payment_failed"].includes(salon.subscriptionStatus)
    if (isBlocked) {
      router.push("/salon/dashboard")
    } else {
      router.push("/salon/agenda")
    }

    setIsChangingSalon(false)
  }

  const handleBackToFranchise = async () => {
    setIsChangingSalon(true)
    setSalonDropdownOpen(false)
    await new Promise((resolve) => setTimeout(resolve, 500))
    router.push(`/franchise/${user?.franchiseId}`)
    setIsChangingSalon(false)
  }

  const handleBackToAdmin = async () => {
    setIsChangingSalon(true)
    setSalonDropdownOpen(false)
    await new Promise((resolve) => setTimeout(resolve, 500))
    setSelectedFranchise(null)
    router.push("/admin/salons")
    setIsChangingSalon(false)
  }

  const handleSelectFranchise = async (franchise: (typeof availableFranchises)[0]) => {
    setIsChangingSalon(true)
    setSalonDropdownOpen(false)
    await new Promise((resolve) => setTimeout(resolve, 500))
    setSelectedFranchise(franchise)
    router.push(`/franchise/${franchise.id}`)
    setIsChangingSalon(false)
  }

  const getPerfilArea = () => {
    if (user?.role === "admin") return "admin"
    if (user?.role === "franchise") return "franchise"
    return "salon"
  }

  const getLogoLink = () => {
    if (user?.role === "admin") return "/admin/salons"
    if (user?.role === "franchise") return `/franchise/${user.franchiseId}`
    return "/salon/agenda"
  }

  const isInSalonArea = pathname.startsWith("/salon")
  const isInAdminArea = pathname.startsWith("/admin")
  const isInFranchiseArea = pathname.startsWith("/franchise")

  const getSelectDisplayText = () => {
    if (isInSalonArea && selectedSalon) return selectedSalon.name
    if (isInFranchiseArea && selectedFranchise) return selectedFranchise.name
    if (isInFranchiseArea && user?.role === "franchise") return "Painel da rede"
    if (isInAdminArea && user?.role === "admin") return "Painel da Easy"
    return "Selecionar salão"
  }

  // Get salons for the currently selected franchise (when admin views a network)
  const getSalonsForCurrentView = () => {
    if (isInFranchiseArea && selectedFranchise) {
      return availableSalons.filter(s => s.franchiseId && s.franchiseId === selectedFranchise.id)
    }
    return availableSalons
  }

  const getSalonStatusIcon = (status: string) => {
    if (["none", "canceled", "payment_failed"].includes(status)) {
      return <IconAlertCircle className="w-3 h-3 text-amber-500" />
    }
    return null
  }

  return (
    <header className="border-b border-border bg-card flex items-center justify-between px-4 md:px-6 py-2 md:py-1 h-auto md:h-16">
      {/* Hamburger menu - mobile only */}
      <button
        onClick={toggleSidebar}
        className="md:hidden flex items-center justify-center w-10 h-10 rounded-lg hover:bg-muted transition-colors mr-2"
        aria-label="Menu"
      >
        <IconMenu2 className="w-6 h-6 text-foreground" />
      </button>

      {isChangingSalon && (
        <div className="fixed inset-0 bg-background/30 backdrop-blur-sm z-[100] flex items-center justify-center">
          <div className="flex flex-col items-center gap-3">
            <LoadingSpinner size="lg" />
            <p className="text-sm font-medium text-foreground">Carregando salão...</p>
          </div>
        </div>
      )}

      <Link href={getLogoLink()} className="flex items-center">
        <img src="/images/image.png" alt="Easy Salon" className="h-6 md:h-7 w-auto" />
      </Link>

      <div className="flex items-center gap-3">
        {/* Web Page and AI buttons moved to user dropdown */}

        {(availableSalons.length > 0 || user?.role === "franchise") && (isInFranchiseArea || isInSalonArea) && (
          <div className="relative hidden md:block" ref={salonDropdownRef}>
            <button
              data-tour="admin-selector"
              onClick={() => setSalonDropdownOpen(!salonDropdownOpen)}
              className={`flex items-center gap-2 px-3 py-2 border border-border rounded-lg transition-colors hover:bg-muted cursor-pointer`}
            >
              <IconBuilding className="w-4 h-4 text-muted-foreground" />
              <span className="text-sm text-foreground">{getSelectDisplayText()}</span>
              <IconChevronDown
                className={`w-4 h-4 text-muted-foreground transition-transform ${salonDropdownOpen ? "rotate-180" : ""}`}
              />
            </button>

            {salonDropdownOpen && (
              <div className="absolute right-0 top-full mt-2 w-72 bg-card border border-border rounded-lg shadow-lg z-50 max-h-96 overflow-y-auto">
                {/* Painel da Easy - only for super admin (role=admin) accessing a franchise/salon */}
                {user?.role === "admin" && (isInFranchiseArea || isInSalonArea) && (
                  <button
                    onClick={handleBackToAdmin}
                    className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-muted transition-colors text-left border-b border-border bg-muted/30`}
                  >
                    <div className="w-8 h-8 rounded-full bg-primary/20 flex items-center justify-center">
                      <IconLayoutDashboard className="w-4 h-4 text-primary" />
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className="text-sm font-medium text-foreground">Painel da Easy</p>
                      <p className="text-xs text-muted-foreground">Voltar à Easy Salon</p>
                    </div>
                  </button>
                )}

                {/* Painel da Rede - when in franchise or salon area */}
                {(isInFranchiseArea || isInSalonArea) && (
                  <button
                    onClick={handleBackToFranchise}
                    className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-muted transition-colors text-left border-b border-border ${
                      !isInSalonArea || user?.role === "franchise" ? "bg-primary/10 border-l-2 border-l-primary" : "bg-muted/30"
                    }`}
                  >
                    <div className="w-8 h-8 rounded-full bg-primary/20 flex items-center justify-center">
                      <IconNetwork className="w-4 h-4 text-primary" />
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className="text-sm font-medium text-foreground">Painel da rede</p>
                      <p className="text-xs text-muted-foreground">{selectedFranchise?.name || "Sua rede"}</p>
                    </div>
                  </button>
                )}

                {/* List of salons */}
                {getSalonsForCurrentView().length > 0 && (
                  <>
                    <div className="px-4 py-2 bg-muted/50 border-b border-border">
                      <p className="text-xs font-medium text-muted-foreground uppercase tracking-wider">
                        {isInFranchiseArea ? `Salões da rede` : "Salões"}
                      </p>
                    </div>
                    {getSalonsForCurrentView().map((salon) => (
                      <button
                        key={salon.id}
                        onClick={() => handleSalonChange(salon)}
                        className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-muted transition-colors text-left border-b border-border last:border-b-0 ${
                          selectedSalon?.id === salon.id && isInSalonArea ? "bg-primary/10 border-l-2 border-l-primary" : ""
                        }`}
                      >
                        <div className="w-8 h-8 rounded-full bg-primary/10 flex items-center justify-center">
                          <IconBuilding className="w-4 h-4 text-primary" />
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-2">
                            <p className="text-sm font-medium text-foreground truncate">{salon.name}</p>
                            {getSalonStatusIcon(salon.subscriptionStatus)}
                          </div>
                          <p className="text-xs text-muted-foreground">{salon.phone}</p>
                        </div>
                      </button>
                    ))}
                  </>
                )}
              </div>
            )}
          </div>
        )}

        <div className="relative" ref={userDropdownRef}>
          <button
            data-tour="profile-button"
            onClick={() => setUserDropdownOpen(!userDropdownOpen)}
            className="flex items-center gap-2 hover:bg-muted px-2 py-1 rounded-lg transition-colors"
          >
            <div className="w-9 h-9 rounded-full bg-primary flex items-center justify-center shrink-0">
              <span className="text-sm font-medium text-primary-foreground">{user?.initials || "??"}</span>
            </div>
            <span className="hidden md:block text-sm text-foreground">{user?.name || "Usuário"}</span>
            <IconChevronDown className="hidden md:block w-4 h-4 text-muted-foreground" />
          </button>

          {userDropdownOpen && (
            <div className="absolute right-0 top-full mt-2 w-56 bg-card border border-border rounded-lg shadow-lg z-50">
              <Link
                href={`/perfil?area=${getPerfilArea()}`}
                onClick={() => setUserDropdownOpen(false)}
                className="flex items-center gap-2 px-4 py-3 hover:bg-muted transition-colors border-b border-border"
              >
                <IconUser className="w-4 h-4 text-muted-foreground" />
                <span className="text-sm text-foreground">Meu perfil</span>
              </Link>
              {/* Selecionar salão - mobile only */}
              {(availableSalons.length > 0 || user?.role === "franchise") && (isInFranchiseArea || isInSalonArea) && (
                <button
                  onClick={() => { setUserDropdownOpen(false); setSalonDrawerOpen(true) }}
                  className="md:hidden w-full flex items-center gap-2 px-4 py-3 hover:bg-muted transition-colors text-left border-b border-border"
                >
                  <IconBuilding className="w-4 h-4 text-muted-foreground" />
                  <span className="text-sm text-foreground">Selecionar salão</span>
                </button>
              )}
              {isInSalonArea && (
                <>
                  <button
                    onClick={() => { setUserDropdownOpen(false); window.open("/agenda-online", "_blank") }}
                    className="w-full flex items-center gap-2 px-4 py-3 hover:bg-muted transition-colors text-left border-b border-border"
                  >
                    <IconAppWindow className="w-4 h-4 text-muted-foreground" />
                    <span className="text-sm text-foreground">Minha página web</span>
                  </button>
                  <button
                    onClick={() => { setUserDropdownOpen(false); window.open("https://wa.me/5541992938071", "_blank") }}
                    className="w-full flex items-center gap-2 px-4 py-3 hover:bg-muted transition-colors text-left border-b border-border"
                  >
                    <IconRobot className="w-4 h-4 text-muted-foreground" />
                    <span className="text-sm text-foreground">Agendamento IA</span>
                  </button>
                </>
              )}
              <button
                onClick={handleLogout}
                className="w-full flex items-center gap-2 px-4 py-3 hover:bg-muted transition-colors text-left"
              >
                <IconLogout className="w-4 h-4 text-[#dd4227]" />
                <span className="text-sm text-[#dd4227]">Log out</span>
              </button>
            </div>
          )}
        </div>
      </div>

      {/* Drawer para selecionar salão - mobile */}
      <Drawer open={salonDrawerOpen} onOpenChange={setSalonDrawerOpen}>
        <DrawerContent>
          <DrawerHeader className="text-left pb-5 border-b border-border">
            <DrawerTitle className="text-left">Selecionar salão</DrawerTitle>
          </DrawerHeader>
          <div className="px-4 pb-6 pt-5 space-y-2">
            {/* Painel da Easy - only for super admin */}
            {user?.role === "admin" && (isInFranchiseArea || isInSalonArea) && (
              <button
                onClick={() => { setSalonDrawerOpen(false); handleBackToAdmin() }}
                className="w-full flex items-center gap-3 px-4 py-3 hover:bg-muted transition-colors text-left border-b border-border bg-muted/30 rounded-lg mb-2"
              >
                <div className="w-8 h-8 rounded-full bg-primary/20 flex items-center justify-center">
                  <IconLayoutDashboard className="w-4 h-4 text-primary" />
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium text-foreground">Painel da Easy</p>
                  <p className="text-xs text-muted-foreground">Voltar à Easy Salon</p>
                </div>
              </button>
            )}

            {/* Painel da Rede */}
            {(isInFranchiseArea || isInSalonArea) && (
              <button
                onClick={() => { setSalonDrawerOpen(false); handleBackToFranchise() }}
                className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-muted transition-colors text-left border border-border rounded-lg mb-2 ${
                  !isInSalonArea || user?.role === "franchise" ? "bg-primary/10 border-primary" : ""
                }`}
              >
                <div className="w-8 h-8 rounded-full bg-primary/20 flex items-center justify-center">
                  <IconNetwork className="w-4 h-4 text-primary" />
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium text-foreground">Painel da rede</p>
                  <p className="text-xs text-muted-foreground">{selectedFranchise?.name || "Sua rede"}</p>
                </div>
              </button>
            )}

            {/* Lista de salões */}
            {getSalonsForCurrentView().length > 0 && (
              <>
                <div className="px-2 py-2 mb-2">
                  <p className="text-xs font-medium text-muted-foreground uppercase tracking-wider">
                    {isInFranchiseArea ? "Salões da rede" : "Salões"}
                  </p>
                </div>
                <div className="space-y-2">
                  {getSalonsForCurrentView().map((salon) => (
                    <button
                      key={salon.id}
                      onClick={() => { setSalonDrawerOpen(false); handleSalonChange(salon) }}
                      className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-muted transition-colors text-left border border-border rounded-lg ${
                        selectedSalon?.id === salon.id && isInSalonArea ? "bg-primary/10 border-primary" : ""
                      }`}
                    >
                      <div className="w-8 h-8 rounded-full bg-primary/10 flex items-center justify-center">
                        <IconBuilding className="w-4 h-4 text-primary" />
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2">
                          <p className="text-sm font-medium text-foreground truncate">{salon.name}</p>
                          {getSalonStatusIcon(salon.subscriptionStatus)}
                        </div>
                        <p className="text-xs text-muted-foreground">{salon.phone}</p>
                      </div>
                    </button>
                  ))}
                </div>
              </>
            )}
          </div>
        </DrawerContent>
      </Drawer>
    </header>
  )
}

"use client"

import { useState, useRef, useEffect } from "react"
import {
  IconChevronDown,
  IconUser,
  IconLogout,
  IconBuilding,
  IconLayoutDashboard,
  IconAlertCircle,
  IconRobot,
  IconAppWindow,
  IconNetwork,
  IconMenu2,
} from "@tabler/icons-react"
import { useSidebar } from "@/contexts/sidebar-context"
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip"
import {
  Drawer,
  DrawerContent,
  DrawerHeader,
  DrawerTitle,
} from "@/components/ui/drawer"

import Link from "next/link"
import { useRouter, usePathname } from "next/navigation"
import { useAuth } from "@/contexts/auth-context"
import { LoadingSpinner } from "@/components/ui/loading-spinner"

export function Header() {
  const router = useRouter()
  const pathname = usePathname()
  const { user, currentSalon, availableSalons, setCurrentSalon, logout, selectedSalon, selectedFranchise, setSelectedSalon, setSelectedFranchise } = useAuth()
  const { toggle: toggleSidebar } = useSidebar()
  const salonDropdownRef = useRef<HTMLDivElement>(null)
  const [userDropdownOpen, setUserDropdownOpen] = useState(false)
  const [salonDropdownOpen, setSalonDropdownOpen] = useState(false)
  const [salonDrawerOpen, setSalonDrawerOpen] = useState(false)
  const [isChangingSalon, setIsChangingSalon] = useState(false)
  const userDropdownRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (userDropdownRef.current && !userDropdownRef.current.contains(event.target as Node)) {
        setUserDropdownOpen(false)
      }
      if (salonDropdownRef.current && !salonDropdownRef.current.contains(event.target as Node)) {
        setSalonDropdownOpen(false)
      }
    }
    document.addEventListener("mousedown", handleClickOutside)
    return () => document.removeEventListener("mousedown", handleClickOutside)
  }, [])

  const handleLogout = () => {
    setUserDropdownOpen(false)
    logout()
    router.push("/login")
  }

  const handleSalonChange = async (salon: (typeof availableSalons)[0]) => {
    setIsChangingSalon(true)
    setSalonDropdownOpen(false)

    await new Promise((resolve) => setTimeout(resolve, 500))

    setSelectedSalon(salon)

    // Verificar se salão está bloqueado
    const isBlocked = ["none", "canceled", "payment_failed"].includes(salon.subscriptionStatus)
    if (isBlocked) {
      router.push("/salon/dashboard")
    } else {
      router.push("/salon/agenda")
    }

    setIsChangingSalon(false)
  }

  const handleBackToFranchise = async () => {
    setIsChangingSalon(true)
    setSalonDropdownOpen(false)
    await new Promise((resolve) => setTimeout(resolve, 500))
    router.push(`/franchise/${user?.franchiseId}`)
    setIsChangingSalon(false)
  }

  const handleBackToAdmin = async () => {
    setIsChangingSalon(true)
    setSalonDropdownOpen(false)
    await new Promise((resolve) => setTimeout(resolve, 500))
    setSelectedFranchise(null)
    router.push("/admin/salons")
    setIsChangingSalon(false)
  }

  const handleSelectFranchise = async (franchise: (typeof availableFranchises)[0]) => {
    setIsChangingSalon(true)
    setSalonDropdownOpen(false)
    await new Promise((resolve) => setTimeout(resolve, 500))
    setSelectedFranchise(franchise)
    router.push(`/franchise/${franchise.id}`)
    setIsChangingSalon(false)
  }

  const getPerfilArea = () => {
    if (user?.role === "admin") return "admin"
    if (user?.role === "franchise") return "franchise"
    return "salon"
  }

  const getLogoLink = () => {
    if (user?.role === "admin") return "/admin/salons"
    if (user?.role === "franchise") return `/franchise/${user.franchiseId}`
    return "/salon/agenda"
  }

  const isInSalonArea = pathname.startsWith("/salon")
  const isInAdminArea = pathname.startsWith("/admin")
  const isInFranchiseArea = pathname.startsWith("/franchise")

  const getSelectDisplayText = () => {
    if (isInSalonArea && selectedSalon) return selectedSalon.name
    if (isInFranchiseArea && selectedFranchise) return selectedFranchise.name
    if (isInFranchiseArea && user?.role === "franchise") return "Painel da rede"
    if (isInAdminArea && user?.role === "admin") return "Painel da Easy"
    return "Selecionar salão"
  }

  // Get salons for the currently selected franchise (when admin views a network)
  const getSalonsForCurrentView = () => {
    if (isInFranchiseArea && selectedFranchise) {
      return availableSalons.filter(s => s.franchiseId && s.franchiseId === selectedFranchise.id)
    }
    return availableSalons
  }

  const getSalonStatusIcon = (status: string) => {
    if (["none", "canceled", "payment_failed"].includes(status)) {
      return <IconAlertCircle className="w-3 h-3 text-amber-500" />
    }
    return null
  }

  return (
    <header className="border-b border-border bg-card flex items-center justify-between px-4 md:px-6 py-2 md:py-1 h-auto md:h-16">
      {/* Hamburger menu - mobile only */}
      <button
        onClick={toggleSidebar}
        className="md:hidden flex items-center justify-center w-10 h-10 rounded-lg hover:bg-muted transition-colors mr-2"
