      {isChangingSalon && (
        <div className="fixed inset-0 bg-background/30 backdrop-blur-sm z-[100] flex items-center justify-center">
          <div className="flex flex-col items-center gap-3">
            <LoadingSpinner size="lg" />
            <p className="text-sm font-medium text-foreground">Carregando salão...</p>
          </div>
        </div>
      )}

      <Link href={getLogoLink()} className="flex items-center">
        <img src="/images/image.png" alt="Easy Salon" className="h-6 md:h-7 w-auto" />
      </Link>

      <div className="flex items-center gap-3">
        {/* Web Page and AI buttons moved to user dropdown */}

        {(availableSalons.length > 0 || user?.role === "franchise") && (isInFranchiseArea || isInSalonArea) && (
          <div className="relative hidden md:block" ref={salonDropdownRef}>
            <button
              data-tour="admin-selector"
              onClick={() => setSalonDropdownOpen(!salonDropdownOpen)}
              className={`flex items-center gap-2 px-3 py-2 border border-border rounded-lg transition-colors hover:bg-muted cursor-pointer`}
            >
              <IconBuilding className="w-4 h-4 text-muted-foreground" />
              <span className="text-sm text-foreground">{getSelectDisplayText()}</span>
              <IconChevronDown
                className={`w-4 h-4 text-muted-foreground transition-transform ${salonDropdownOpen ? "rotate-180" : ""}`}
              />
            </button>

            {salonDropdownOpen && (
              <div className="absolute right-0 top-full mt-2 w-72 bg-card border border-border rounded-lg shadow-lg z-50 max-h-96 overflow-y-auto">
                {/* Painel da Easy - only for super admin (role=admin) accessing a franchise/salon */}
                {user?.role === "admin" && (isInFranchiseArea || isInSalonArea) && (
                  <button
                    onClick={handleBackToAdmin}
                    className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-muted transition-colors text-left border-b border-border bg-muted/30`}
                  >
                    <div className="w-8 h-8 rounded-full bg-primary/20 flex items-center justify-center">
                      <IconLayoutDashboard className="w-4 h-4 text-primary" />
