                      <p className="text-xs text-muted-foreground">{selectedFranchise?.name || "Sua rede"}</p>
                    </div>
                  </button>
                )}

                {/* List of salons */}
                {getSalonsForCurrentView().length > 0 && (
                  <>
                    <div className="px-4 py-2 bg-muted/50 border-b border-border">
                      <p className="text-xs font-medium text-muted-foreground uppercase tracking-wider">
                        {isInFranchiseArea ? `Salões da rede` : "Salões"}
                      </p>
                    </div>
                    {getSalonsForCurrentView().map((salon) => (
                      <button
                        key={salon.id}
                        onClick={() => handleSalonChange(salon)}
                        className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-muted transition-colors text-left border-b border-border last:border-b-0 ${
                          selectedSalon?.id === salon.id && isInSalonArea ? "bg-primary/10 border-l-2 border-l-primary" : ""
                        }`}
                      >
                        <div className="w-8 h-8 rounded-full bg-primary/10 flex items-center justify-center">
                          <IconBuilding className="w-4 h-4 text-primary" />
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-2">
                            <p className="text-sm font-medium text-foreground truncate">{salon.name}</p>
                            {getSalonStatusIcon(salon.subscriptionStatus)}
                          </div>
                          <p className="text-xs text-muted-foreground">{salon.phone}</p>
                        </div>
                      </button>
                    ))}
                  </>
                )}
              </div>
            )}
          </div>
        )}

        <div className="relative" ref={userDropdownRef}>
          <button
            data-tour="profile-button"
            onClick={() => setUserDropdownOpen(!userDropdownOpen)}
