import { SubscriptionAlertModal } from "@/components/modals/SubscriptionAlertModal";
import { useAuth } from "@/contexts/AuthContext";
import { useSelectedSalon } from "@/hooks/useSelectedSalon";
import { salonService } from "@/services/salonService";
import { Salon } from "@/types/salon";
import { getInitials } from "@/utils/imageUtils";
import {
  IconAlertCircle as AlertCircle,
  IconAppWindow as AppWindow,
  IconRobot as Bot,
  IconBuilding as Building2,
  IconChevronDown as ChevronDown,
  IconLayoutDashboard as LayoutDashboard,
  IconLogout as LogOut,
  IconMenu2 as Menu,
  IconUser as User,
} from "@tabler/icons-react";
import { useEffect, useRef, useState } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import { Drawer, DrawerContent, DrawerHeader, DrawerTitle } from "@/components/ui/drawer";
import easySalonLogo from "@/assets/easy-logo.svg";

interface HeaderProps {
  onMenuClick?: () => void;
}

export function Header({ onMenuClick }: HeaderProps) {
  const navigate = useNavigate();
  const location = useLocation();
  const { selectedSalon, updateSelectedSalon } = useSelectedSalon();
  const { logout, user } = useAuth();
  const [salons, setSalons] = useState<Salon[]>([]);
  const [loadingSalons, setLoadingSalons] = useState(true);
  const [showExpiredModal, setShowExpiredModal] = useState(false);
  const [pendingSalon, setPendingSalon] = useState<Salon | null>(null);
  const [salonDrawerOpen, setSalonDrawerOpen] = useState(false);
  const [salonDropdownOpen, setSalonDropdownOpen] = useState(false);
  const [userDropdownOpen, setUserDropdownOpen] = useState(false);

  const salonDropdownRef = useRef<HTMLDivElement>(null);
  const userDropdownRef = useRef<HTMLDivElement>(null);

  const isSalonArea = location.pathname.startsWith("/salon");
  const isAdminArea = location.pathname.startsWith("/admin");

  // Close dropdowns on outside click
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (salonDropdownRef.current && !salonDropdownRef.current.contains(event.target as Node)) {
        setSalonDropdownOpen(false);
      }
      if (userDropdownRef.current && !userDropdownRef.current.contains(event.target as Node)) {
        setUserDropdownOpen(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // Fetch salons on mount
  useEffect(() => {
    const fetchSalons = async () => {
      try {
        setLoadingSalons(true);
        const response = await salonService.list();
        // @ts-ignore - Backend response might be paginated or raw array
        const data = response.data || response;
        setSalons(Array.isArray(data) ? data : []);
      } catch (error) {
        console.error("Error fetching salons:", error);
        setSalons([]);
      } finally {
        setLoadingSalons(false);
      }
    };
    fetchSalons();
  }, [user]);

  const isPlanExpired = (salon: Salon) => {
    return (
      salon.subscription?.status === "past_due" ||
      salon.subscription?.status === "canceled" ||
      salon.subscription?.status === "unpaid"
    );
  };

  const handleSalonSelect = (salon: Salon) => {
    setSalonDropdownOpen(false);
    if (isPlanExpired(salon)) {
      setPendingSalon(salon);
      setShowExpiredModal(true);
      return;
    }
    updateSelectedSalon(salon);
    if (location.pathname === "/salon/agenda") {
      setTimeout(() => { window.location.reload(); }, 100);
    } else {
      navigate("/salon/agenda");
    }
  };

  const handleExpiredPlanConfirm = () => {
    if (pendingSalon) {
      updateSelectedSalon(pendingSalon);
      setShowExpiredModal(false);
      navigate("/salon/my-plan");
    }
  };

  const handleLogout = () => {
    setUserDropdownOpen(false);
    logout();
    navigate("/login");
  };

  const handleProfile = () => {
    setUserDropdownOpen(false);
    navigate("/profile");
  };

  const handleAdminPanel = () => {
    setSalonDropdownOpen(false);
    navigate("/admin/salons");
  };

  const filteredSalons = salons.filter((s) =>
    user?.role === "Easy Salon" ||
    user?.role === "Tenant Admin" ||
    user?.salonId === s.id
  );

  const salonListItems = filteredSalons.map((salon) => {
    const expired = isPlanExpired(salon);
    const isSelected = selectedSalon?.id === salon.id;
    return (
      <button
        key={salon.id}
        onClick={() => handleSalonSelect(salon)}
        className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-muted transition-colors text-left border-b border-border last:border-b-0 ${
          isSelected ? "bg-primary/10 border-l-2 border-l-primary" : ""
        } ${expired ? "bg-red-50/50" : ""}`}
      >
        <div className={`w-8 h-8 rounded-full flex items-center justify-center ${expired ? "bg-red-100/50" : "bg-primary/10"}`}>
          <Building2 className={`w-4 h-4 ${expired ? "text-red-500" : "text-primary"}`} />
        </div>
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2">
            <p className="text-sm font-medium text-foreground truncate">{salon.name}</p>
            {expired && <AlertCircle className="w-3 h-3 text-red-500" />}
          </div>
          <p className="text-xs text-muted-foreground">{salon.phone || "(s/ contato)"}</p>
        </div>
      </button>
    );
  });

  return (
    <>
      <header className="h-16 border-b bg-card px-4 md:px-6 flex items-center justify-between flex-shrink-0 relative">
        {/* Left: hamburger (mobile-only) + logo (desktop-only) */}
        <div className="flex items-center gap-3">
          <button
            onClick={onMenuClick}
            aria-label="Toggle Menu"
            className="w-10 h-10 flex items-center justify-center hover:bg-muted rounded-lg transition-colors md:hidden"
          >
            <Menu className="w-6 h-6 text-foreground" />
          </button>
          <img src={easySalonLogo} alt="Easy Salon" className="hidden md:block h-7 w-auto" />
        </div>

        {/* Logo — mobile only, absolutely centered */}
        <img
          src={easySalonLogo}
          alt="Easy Salon"
          className="md:hidden absolute left-1/2 -translate-x-1/2 h-6 w-auto"
        />

        {/* Right side controls */}
        <div className="flex items-center gap-2 md:gap-4">

          {/* Salon selector — desktop only */}
          <div className="relative hidden md:block" ref={salonDropdownRef}>
            <button
              onClick={() => setSalonDropdownOpen(!salonDropdownOpen)}
              className="flex items-center gap-2 px-3 py-2 border border-border rounded-lg transition-colors hover:bg-muted cursor-pointer h-10"
            >
              <Building2 className="w-4 h-4 text-muted-foreground" />
              <span className="text-sm text-foreground">
                {isAdminArea ? "Selecionar Salão" : selectedSalon?.name || "Selecionar Salão"}
              </span>
              <ChevronDown className={`h-4 w-4 text-muted-foreground transition-transform ${salonDropdownOpen ? "rotate-180" : ""}`} />
            </button>

            {salonDropdownOpen && (
              <div className="absolute right-0 top-full mt-2 w-72 bg-card border border-border rounded-lg shadow-lg z-50 overflow-hidden">
                <div className="max-h-96 overflow-y-auto">
                  {/* Admin/Network panels */}
                  {(user?.role === "Easy Salon" || user?.role === "Tenant Admin") && (
                    <button
                      onClick={handleAdminPanel}
                      className="w-full flex items-center gap-3 px-4 py-3 hover:bg-muted transition-colors text-left border-b border-border bg-muted/30"
                    >
                      <div className="w-8 h-8 rounded-full bg-primary/20 flex items-center justify-center">
                        <LayoutDashboard className="w-4 h-4 text-primary" />
                      </div>
                      <div className="flex-1 min-w-0">
                        <p className="text-sm font-medium text-foreground">Painel da Easy</p>
                        <p className="text-xs text-muted-foreground">Voltar à Easy Salon</p>
                      </div>
                    </button>
                  )}

                  {/* Section header */}
                  <div className="px-4 py-2 bg-muted/50 border-b border-border">
                    <p className="text-xs font-medium text-muted-foreground uppercase tracking-wider">Salões</p>
                  </div>

                  {loadingSalons ? (
                    <div className="px-2 py-4 text-center text-sm text-muted-foreground">Carregando salões...</div>
                  ) : filteredSalons.length === 0 ? (
                    <div className="px-2 py-4 text-center text-sm text-muted-foreground">Nenhum salão disponível</div>
                  ) : (
                    salonListItems
                  )}
                </div>
              </div>
            )}
          </div>

          {/* User dropdown */}
          <div className="relative" ref={userDropdownRef}>
            <button
              onClick={() => setUserDropdownOpen(!userDropdownOpen)}
              className="flex items-center gap-2 md:gap-3 px-2 md:px-3 py-1.5 hover:bg-muted rounded-lg transition-colors"
            >
              <div className="w-9 h-9 rounded-full bg-primary flex items-center justify-center flex-shrink-0">
                <span className="text-primary-foreground text-xs font-semibold">
                  {getInitials(user?.name || "Usuário")}
                </span>
              </div>
              <span className="font-medium text-sm hidden sm:inline-block">{user?.name || "Usuário"}</span>
              <ChevronDown className={`h-4 w-4 text-muted-foreground hidden sm:block transition-transform ${userDropdownOpen ? "rotate-180" : ""}`} />
            </button>

            {userDropdownOpen && (
              <div className="absolute right-0 top-full mt-2 w-56 bg-card border border-border rounded-lg shadow-lg z-50">
                <button
                  onClick={handleProfile}
                  className="w-full flex items-center gap-2 px-4 py-3 hover:bg-muted transition-colors text-left border-b border-border"
                >
                  <User className="w-4 h-4 text-muted-foreground" />
                  <span className="text-sm text-foreground">Meu perfil</span>
                </button>

                {/* Selecionar salão — mobile only */}
                {isSalonArea && (
                  <button
                    onClick={() => { setUserDropdownOpen(false); setSalonDrawerOpen(true); }}
                    className="md:hidden w-full flex items-center gap-2 px-4 py-3 hover:bg-muted transition-colors text-left border-b border-border"
                  >
                    <Building2 className="w-4 h-4 text-muted-foreground" />
                    <span className="text-sm text-foreground">Selecionar salão</span>
                  </button>
                )}

                {isSalonArea && (
                  <>
                    <button
                      onClick={() => { setUserDropdownOpen(false); window.open("/agenda-online", "_blank"); }}
                      className="md:hidden w-full flex items-center gap-2 px-4 py-3 hover:bg-muted transition-colors text-left border-b border-border"
                    >
                      <AppWindow className="w-4 h-4 text-muted-foreground" />
                      <span className="text-sm text-foreground">Minha página web</span>
                    </button>
                    <button
                      onClick={() => { setUserDropdownOpen(false); window.open("https://wa.me/5541992938071", "_blank"); }}
                      className="md:hidden w-full flex items-center gap-2 px-4 py-3 hover:bg-muted transition-colors text-left border-b border-border"
                    >
                      <Bot className="w-4 h-4 text-muted-foreground" />
                      <span className="text-sm text-foreground">Agendamento IA</span>
                    </button>
                  </>
                )}

                <button
                  onClick={handleLogout}
                  className="w-full flex items-center gap-2 px-4 py-3 hover:bg-muted transition-colors text-left"
                >
                  <LogOut className="w-4 h-4 text-[#dd4227]" />
                  <span className="text-sm text-[#dd4227]">Log out</span>
                </button>
              </div>
            )}
          </div>
        </div>
      </header>

      <SubscriptionAlertModal
        isOpen={showExpiredModal}
        onConfirm={handleExpiredPlanConfirm}
      />

      {/* Drawer para selecionar salão — mobile only */}
      <Drawer open={salonDrawerOpen} onOpenChange={setSalonDrawerOpen}>
        <DrawerContent>
          <DrawerHeader className="text-left pb-5 border-b border-border">
            <DrawerTitle className="text-left">Selecionar salão</DrawerTitle>
          </DrawerHeader>
          <div className="px-4 pb-6 pt-5 space-y-2 overflow-y-auto flex-1 min-h-0">
            {(user?.role === "Easy Salon" || user?.role === "Tenant Admin") && (
              <button
                onClick={() => { setSalonDrawerOpen(false); navigate("/admin/salons"); }}
                className="w-full flex items-center gap-3 px-4 py-3 hover:bg-muted transition-colors text-left border border-border rounded-lg bg-muted/30"
              >
                <div className="w-8 h-8 rounded-full bg-primary/20 flex items-center justify-center">
                  <LayoutDashboard className="w-4 h-4 text-primary" />
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium text-foreground">Painel da Easy</p>
                  <p className="text-xs text-muted-foreground">Voltar à Easy Salon</p>
                </div>
              </button>
            )}

            {loadingSalons ? (
              <p className="text-sm text-muted-foreground text-center py-4">Carregando salões...</p>
            ) : (
              <div className="space-y-2">
                {filteredSalons.map((salon) => {
                  const expired = isPlanExpired(salon);
                  const isSelected = selectedSalon?.id === salon.id;
                  return (
                    <button
                      key={salon.id}
                      onClick={() => { setSalonDrawerOpen(false); handleSalonSelect(salon); }}
                      className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-muted transition-colors text-left border rounded-lg ${
                        isSelected ? "bg-primary/10 border-primary" : "border-border"
                      } ${expired ? "opacity-70" : ""}`}
                    >
                      <div className="w-8 h-8 rounded-full bg-primary/10 flex items-center justify-center">
                        <Building2 className={`w-4 h-4 ${expired ? "text-destructive" : "text-primary"}`} />
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2">
                          <p className="text-sm font-medium text-foreground truncate">{salon.name}</p>
                          {expired && <AlertCircle className="w-3 h-3 text-destructive" />}
                        </div>
                        <p className="text-xs text-muted-foreground">{salon.phone || "(s/ contato)"}</p>
                      </div>
                    </button>
                  );
                })}
              </div>
            )}
          </div>
        </DrawerContent>
      </Drawer>
    </>
  );
