              </button>
              <button
                onClick={() => window.open("https://wa.me/5541992938071", "_blank")}
                className="hidden md:flex items-center gap-2 px-3 py-2 border border-border rounded-lg hover:bg-muted transition-colors text-sm text-foreground h-10"
              >
                <Bot className="w-4 h-4 text-muted-foreground" />
                Agendamento IA
              </button>
