              </div>
              <span className="font-medium text-sm hidden sm:inline-block">{user?.name || "Usuário"}</span>
              <ChevronDown className={`h-4 w-4 text-muted-foreground hidden sm:block transition-transform ${userDropdownOpen ? "rotate-180" : ""}`} />
