                </button>

                {/* Selecionar salão — mobile only */}
                {isSalonArea && (
                  <button
                    onClick={() => { setUserDropdownOpen(false); setSalonDrawerOpen(true); }}
                    className="md:hidden w-full flex items-center gap-2 px-4 py-3 hover:bg-muted transition-colors text-left border-b border-border"
                  >
                    <Building2 className="w-4 h-4 text-muted-foreground" />
                    <span className="text-sm text-foreground">Selecionar salão</span>
                  </button>
                )}

                {isSalonArea && (
                  <>
                    <button
                      onClick={() => { setUserDropdownOpen(false); window.open("/agenda-online", "_blank"); }}
                      className="w-full flex items-center gap-2 px-4 py-3 hover:bg-muted transition-colors text-left border-b border-border"
                    >
                      <AppWindow className="w-4 h-4 text-muted-foreground" />
                      <span className="text-sm text-foreground">Minha página web</span>
                    </button>
                    <button
                      onClick={() => { setUserDropdownOpen(false); window.open("https://wa.me/5541992938071", "_blank"); }}
                      className="w-full flex items-center gap-2 px-4 py-3 hover:bg-muted transition-colors text-left border-b border-border"
