            ) : (
              <div className="space-y-2">
                {filteredSalons.map((salon) => {
                  const expired = isPlanExpired(salon);
                  const isSelected = selectedSalon?.id === salon.id;
                  return (
                    <button
                      key={salon.id}
                      onClick={() => { setSalonDrawerOpen(false); handleSalonSelect(salon); }}
                      className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-muted transition-colors text-left border rounded-lg ${
                        isSelected ? "bg-primary/10 border-primary" : "border-border"
                      } ${expired ? "opacity-70" : ""}`}
                    >
                      <div className="w-8 h-8 rounded-full bg-primary/10 flex items-center justify-center">
                        <Building2 className={`w-4 h-4 ${expired ? "text-destructive" : "text-primary"}`} />
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2">
